import React, { useState } from 'react';
import TopBar from '../components/TopBar';
import Navbar from '../components/Navbar';
import { Footer, WhatsAppFloat } from '../components/Sections';
import useInView from '../hooks/useInView';
import styles from './Projects.module.css';

const PROJECTS = [
  {
    category: 'Emissions Monitoring',
    title: 'Kigali Fleet Emissions Tracking',
    desc: 'Deployed real-time emissions monitoring devices across a 20-vehicle logistics fleet in Kigali, enabling live compliance reporting for the Transport Ministry.',
    tags: ['IoT', 'Compliance', 'Fleet'],
    status: 'Completed',
    year: '2023',
    img: '/img/one.jpg',
  },
  {
    category: 'Electric Vehicles',
    title: 'Rural E-Tricycle Pilot — Southern Province',
    desc: 'Launched 5 electric cargo tricycles for an agricultural cooperative in the Southern Province, reducing delivery costs and eliminating emissions on rural routes.',
    tags: ['Electric', 'Rural', 'Agriculture'],
    status: 'Ongoing',
    year: '2024',
    img: '/img/two.jpg',
  },
  {
    category: 'IoT Dashboard',
    title: 'Multi-Fleet IoT Management Platform',
    desc: 'Built and deployed a centralised IoT dashboard for 3 transport companies, providing live vehicle tracking, emissions data, and automated maintenance alerts.',
    tags: ['IoT', 'Dashboard', 'Analytics'],
    status: 'Ongoing',
    year: '2024',
    img: '/img/three.jpg',
  },
  {
    category: 'Inspection & Repair',
    title: 'Emission Compliance Repair Programme',
    desc: 'Partnered with IOM Rwanda to inspect and repair high-emission vehicles across Kigali, bringing 30+ vehicles into full regulatory compliance.',
    tags: ['Repair', 'Compliance', 'Partnership'],
    status: 'Completed',
    year: '2023',
    img: '/img/four.jpg',
  },
  {
    category: 'Green Installation',
    title: 'Green Vehicle System Rollout',
    desc: 'Installed green vehicle emission reduction systems across a government agency fleet, cutting average emissions by over 40% per vehicle.',
    tags: ['Installation', 'Government', 'Green'],
    status: 'Completed',
    year: '2022',
    img: '/img/one.jpg',
  },
  {
    category: 'Analytics',
    title: 'National Emissions Data Dashboard',
    desc: 'Developed an analytics dashboard for NCST Rwanda to visualise national vehicle emissions trends and support data-driven policy decisions.',
    tags: ['Analytics', 'Policy', 'National'],
    status: 'Ongoing',
    year: '2025',
    img: '/img/two.jpg',
  },
];

const CATEGORIES = ['All', ...new Set(PROJECTS.map(p => p.category))];

function FadeIn({ children, delay = 0 }) {
  const [ref, visible] = useInView();
  return (
    <div ref={ref} style={{
      opacity: visible ? 1 : 0,
      transform: visible ? 'translateY(0)' : 'translateY(28px)',
      transition: `opacity 0.65s ${delay}s ease, transform 0.65s ${delay}s ease`,
    }}>
      {children}
    </div>
  );
}

export default function Projects() {
  const [active, setActive] = useState('All');

  const filtered = active === 'All' ? PROJECTS : PROJECTS.filter(p => p.category === active);

  return (
    <>
      <TopBar />
      <Navbar />

      {/* Hero */}
      <div className={styles.hero}>
        <div className={styles.heroOverlay} />
        <div className={styles.heroContent}>
          <FadeIn>
            <p className={styles.heroLabel}>Our projects</p>
            <h1 className={styles.heroTitle}>Real impact, <span>real results.</span></h1>
            <p className={styles.heroSub}>From fleet emissions monitoring to electric tricycle deployments — here's what we've built across Rwanda.</p>
          </FadeIn>
        </div>
      </div>

      {/* Filter tabs */}
      <section className={styles.section}>
        <div className={styles.container}>
          <FadeIn>
            <div className={styles.filters}>
              {CATEGORIES.map(cat => (
                <button
                  key={cat}
                  className={`${styles.filterBtn} ${active === cat ? styles.filterActive : ''}`}
                  onClick={() => setActive(cat)}
                >
                  {cat}
                </button>
              ))}
            </div>
          </FadeIn>

          <div className={styles.grid}>
            {filtered.map((p, i) => (
              <FadeIn key={i} delay={i * 0.08}>
                <div className={styles.card}>
                  <div className={styles.cardImg} style={{ backgroundImage: `url(${p.img})` }}>
                    <span className={`${styles.status} ${p.status === 'Ongoing' ? styles.statusOngoing : styles.statusDone}`}>
                      {p.status}
                    </span>
                  </div>
                  <div className={styles.cardBody}>
                    <p className={styles.cardCategory}>{p.category} · {p.year}</p>
                    <h3>{p.title}</h3>
                    <p className={styles.cardDesc}>{p.desc}</p>
                    <div className={styles.tags}>
                      {p.tags.map((t, j) => (
                        <span key={j} className={styles.tag}>{t}</span>
                      ))}
                    </div>
                  </div>
                </div>
              </FadeIn>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <div className={styles.cta}>
        <FadeIn>
          <h2>Have a project in mind?</h2>
          <p>Let's work together to build clean mobility solutions for your organisation.</p>
          <div className={styles.ctaBtns}>
            <a href="/contact" className={styles.ctaWhite}>Start a conversation</a>
            <a href="https://wa.me/250796895138" target="_blank" rel="noreferrer" className={styles.ctaOutline}>💬 WhatsApp us</a>
          </div>
        </FadeIn>
      </div>

      <Footer />
      <WhatsAppFloat />
    </>
  );
}
